import{assert}from"./asserts.js";function clamp(t,e,r){return Math.min(Math.max(t,e),r)}const cosh=function(){let t;return t="cosh"in Math?Math.cosh:function(t){t=Math.exp(t);return(t+1/t)/2}}();function roundUpToPowerOfTwo(t){return assert(0<t,29),Math.pow(2,Math.ceil(Math.log(t)/Math.LN2))}function squaredSegmentDistance(t,e,r,n,o,a){var s,u=o-r,c=a-n;return 0==u&&0==c||(1<(s=((t-r)*u+(e-n)*c)/(u*u+c*c))?(r=o,n=a):0<s&&(r+=u*s,n+=c*s)),squaredDistance(t,e,r,n)}function squaredDistance(t,e,r,n){r-=t,t=n-e;return r*r+t*t}function solveLinearSystem(o){var a=o.length;for(let n=0;n<a;n++){let e=n,r=Math.abs(o[n][n]);for(let t=n+1;t<a;t++){var s=Math.abs(o[t][n]);s>r&&(r=s,e=t)}if(0===r)return null;var t=o[e];o[e]=o[n],o[n]=t;for(let e=n+1;e<a;e++){var u=-o[e][n]/o[n][n];for(let t=n;t<a+1;t++)n==t?o[e][t]=0:o[e][t]+=u*o[n][t]}}const r=new Array(a);for(let e=a-1;0<=e;e--){r[e]=o[e][a]/o[e][e];for(let t=e-1;0<=t;t--)o[t][a]-=o[t][e]*r[e]}return r}function toDegrees(t){return 180*t/Math.PI}function toRadians(t){return t*Math.PI/180}function modulo(t,e){t%=e;return t*e<0?t+e:t}function lerp(t,e,r){return t+r*(e-t)}export{clamp,cosh,roundUpToPowerOfTwo,squaredSegmentDistance,squaredDistance,solveLinearSystem,toDegrees,toRadians,modulo,lerp};